// // This is a 3-bit synchronous binary counter with a synchronous clear input (clear) that sets the counter to 8, an enable input (en) to disable counting, and a carry-out output (carry) which goes low when the counter reaches its minimum value (0).
module binary_counter (
  input clk,
  input clear,
  input en,
  output reg [2:0] count,
  output carry
);always @(posedge clk) begin
	if (clear) begin
		count <= 3'b000;
	end else if (en) begin
		count <= count + 1;
	end
end

assign carry = (count == 3'b111);

endmodule
